<div id="overlay" class="overlay hidden">
  <div class="dialog">
    <h2 class="dialog-title">Введите ключ подключения</h2>
    <input
      type="text"
      id="connection-key"
      class="dialog-input"
      placeholder="Введите ключ"
    />
    <div class="dialog-actions">
      <button class="dialog-button" onclick="closeDialog()">Закрыть</button>
      <button class="dialog-button primary" onclick="connect()">Подключиться</button>
    </div>
  </div>
</div>

